"use strict";(self.webpackChunkstudy_journal=self.webpackChunkstudy_journal||[]).push([["554"],{2438(n,e,a){a.r(e),a.d(e,{metadata:()=>t,default:()=>d,frontMatter:()=>o,contentTitle:()=>r,toc:()=>l,assets:()=>c});var t=JSON.parse('{"id":"Programming Languages/bash","title":"Notes on Bash","description":"Basics","source":"@site/docs/Programming Languages/bash.mdx","sourceDirName":"Programming Languages","slug":"/Programming Languages/bash","permalink":"/study-journal/docs/Programming Languages/bash","draft":false,"unlisted":false,"editUrl":"https://github.com/lima-emanuel/study-journal/tree/main/packages/create-docusaurus/templates/shared/docs/Programming Languages/bash.mdx","tags":[],"version":"current","sidebarPosition":2,"frontMatter":{"sidebar_position":2},"sidebar":"tutorialSidebar","previous":{"title":"Notes on Algorithms","permalink":"/study-journal/docs/Programming Languages/algo"},"next":{"title":"Notes on C","permalink":"/study-journal/docs/Programming Languages/c"}}'),s=a(1684),i=a(506);let o={sidebar_position:2},r="Notes on Bash",c={},l=[{value:"Basics",id:"basics",level:2}];function u(n){let e={code:"code",h1:"h1",h2:"h2",header:"header",pre:"pre",...(0,i.R)(),...n.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(e.header,{children:(0,s.jsx)(e.h1,{id:"notes-on-bash",children:"Notes on Bash"})}),"\n",(0,s.jsx)(e.h2,{id:"basics",children:"Basics"}),"\n",(0,s.jsx)(e.pre,{children:(0,s.jsx)(e.code,{className:"language-bash",children:'# This is a comment\n\n# A shebang tells the operating system which script engine should be used to run the script:\n#!/usr/bin/env bash\n\n# A single command can be written in multiple lines if each line ends in a backslash:\ncurl --request GET -sL \\\n    --user-agent \'Shellman\' \\\n    --cookie \'key=value\' \\\n    --url \'http://example.com\'\n\n# One can write multiple commands in a single line and separate them by semicolon (;):\nvar1=2; var2=3; var3="hello"\n\n# Variable assignment. Variables are case sensitive. Spaces are not allowed:\nfirstName=Pedro\n\n# Variable reading. To access a variable value prefix it with $:\necho "$firstName"\necho "${firstName}"\n\n# Spaces have special meaning.\nfirstName = Pedro\n# means command firstName is receiving arguments = and Pedro\n\n# Always surround variables in "" when accessing their values if they may contain whitespaces:\nfileName="some file.txt"\nrm ${fileName}\n\n# To concat variables and interpolate the string:\na="abc"\nb="def"\nc="ghi"\necho "${a}a ${b}b ${c}c"\n# abca defb ghic\n# Only double quotes expand variables and preserve special meaning to symbols. Single quotes make it raw.\n\n# To assign a variable if and only if it has no value currently, use the default value snippet:\n: "${variable:=default}"\n\n# 3 types exist: Number, String and Array\nvar1=123\nvar2="oi, gente"\nmyArray=("one" "two" "three")\nmyArray2=(\n    "four"\n    "five"\n    "six"\n)\necho "${myArray[@]}" # one two three\necho "${myArray2[@]}" # four five six\necho "${myArray[0]}" # one\necho "${myArray2[2]}" # six\n\n# Functions:\nfunction my_func () {\n    echo "${1}"\n}\nmy_func hello    # hello\n\n# Define functions before you can use them. If function B calls function A, then function A definition should precede definition of function B.\n\n# $0 - Name of the script\n# $1 to $9 - Arguments to the script. $1 is the first argument and so on.\n# $@ - All the arguments\n# $# - Number of arguments\n# $? - Return code of the previous command\n# $$ - Process Identification Number (PID) for the current script\n# !! - Entire last command, including arguments\n# $_ - Last argument from the last command\n\n# To return, use echo\n# return keyword only for integer status code (0 - 255) for functions\n# exit keyword only for integer status code (0 - 255) for the entire script\n# 0 is no error, the others, different kind of errors\n\n# To store the output of commands inside variables:\noutput=$(command)\n\n# check last command failure:\nif [[ $? != 0 ]]; then\n    echo "command failed"\nfi\n\n# check last command success:\nif [[ $? == 0 ]]; then\n    echo "command failed"\nfi\n\n# On a script, a flag is used for boolean values and its presence means True while Switch accepts argument(s).\n# A snippet to handle them:\nPOSITIONAL=()\nwhile [[ $# > 0 ]]; do # while arguments count > 0\n    case "${1}" in\n        -f|--flag)\n        echo flag: ${1}\n        shift # shift once since flags have no values\n        ;;\n        -s|--switch)\n        echo switch ${1} with value: ${2}\n        shift 2 # shift twice to bypass switch and its value\n        ;;\n        *) # unknown flag/switch\n        POSITIONAL+=("${1}")\n        shift\n        ;;\n    esac # end of case.\ndone\nset -- "${POSITIONAL[@]}" # restore positional params\n# replace -f|--flag with desired flag, i.e. -v|--verbose and on the next lines (before shift) do whatever you need.\n\n# Good structure for scripts:\n# 1. shebang\n# 2. summary\n# 3. handler functions region (if any)\n# 4. event handlers region (if any)\n# 5. animation frames region (if any)\n# 6. functions region\n# 7. argument parsing\n# 8. setting default variable values\n# 9. rest of code (minimize it to function calls)\n\n# Summary is:\n# Title: script\n# Description: a script\n# Author: Fulano <fulano@gmail.com>\n# Date: 2019-01-06\n# Version: 1.0.0\n#\n# Exit codes\n# ==========\n# 0 no error\n# 1 script interrupted\n# 2 error description\n\n# Booleans:\n# true and false\n# || is or\n# && is and\n\n# Process substitution:\n<( CMD )\n# will execute CMD and place the output in a temporary file and substitute the <() with that file\u2019s name.\ndiff <(ls foo) <(ls bar)\n# will show differences between files in dirs foo and bar.\n\n# Iterate through the arguments provided, grep for the string foobar, and append it to the file as a comment if it\u2019s not found:\nfor file in "$@"; do\n    grep foobar "$file" > /dev/null 2> /dev/null\n    # When pattern is not found, grep has exit status 1\n    # We redirect STDOUT and STDERR to a null register since we do not care about them\n    if [[ $? -ne 0 ]]; then\n        echo "File $file does not have any foobar, adding one"\n        echo "# foobar" >> "$file"\n    fi\ndone\n\n# Globbing:\n# ? match one\n# * match any\n# {} expand on common substring\n*{.py,.sh} # means all .py and .sh files\n'})})]})}function d(n={}){let{wrapper:e}={...(0,i.R)(),...n.components};return e?(0,s.jsx)(e,{...n,children:(0,s.jsx)(u,{...n})}):u(n)}},506(n,e,a){a.d(e,{R:()=>o,x:()=>r});var t=a(2888);let s={},i=t.createContext(s);function o(n){let e=t.useContext(i);return t.useMemo(function(){return"function"==typeof n?n(e):{...e,...n}},[e,n])}function r(n){let e;return e=n.disableParentContext?"function"==typeof n.components?n.components(s):n.components||s:o(n.components),t.createElement(i.Provider,{value:e},n.children)}}}]);